import { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {

  const [city, setCity] = useState("");
  const [weather, setWeather] = useState(null);

  const [darkMode, setDarkMode] = useState(true);

  const [background, setBackground] = useState(
    "https://images.pexels.com/photos/158163/clouds-cloudporn-weather-lookup-158163.jpeg"
  );

  const getWeather = async () => {

    if(city.trim() === ""){
      alert("Please enter city name");
      return;
    }

    try {

      const response = await axios.get(
        `http://localhost:5000/weather/${city}`
      );

      setWeather(response.data);

      const condition =
        response.data.weather[0].main;

      /* Dynamic Backgrounds */

      if(condition === "Clouds"){

        setBackground(
          "https://images.pexels.com/photos/158163/clouds-cloudporn-weather-lookup-158163.jpeg"
        );

      }

      else if(condition === "Rain"){

        setBackground(
          "https://images.pexels.com/photos/110874/pexels-photo-110874.jpeg"
        );

      }

      else if(condition === "Clear"){

        setBackground(
          "https://images.pexels.com/photos/414171/pexels-photo-414171.jpeg"
        );

      }

      else if(condition === "Snow"){

        setBackground(
          "https://images.pexels.com/photos/688660/pexels-photo-688660.jpeg"
        );

      }

      else if(condition === "Thunderstorm"){

        setBackground(
          "https://images.pexels.com/photos/53459/lightning-storm-weather-sky-53459.jpeg"
        );

      }

      else if(condition === "Mist"){

        setBackground(
          "https://images.pexels.com/photos/167699/pexels-photo-167699.jpeg"
        );

      }

      else{

        setBackground(
          "https://images.pexels.com/photos/531880/pexels-photo-531880.jpeg"
        );

      }

    } catch (error) {

      alert("City not found");

    }
  };

  const toggleTheme = () => {

    setDarkMode(!darkMode);

  };

  return (

    <div

      className={darkMode ? "app dark" : "app light"}

      style={{

        background: `
          linear-gradient(
            rgba(0,0,0,0.35),
            rgba(0,0,0,0.45)
          ),
          url(${background}?${new Date().getTime()})
        `,

        backgroundSize: "cover",

        backgroundPosition: "center",

        backgroundRepeat: "no-repeat",

        transition: "0.5s ease"

      }}
    >

      <div className="container">

        <button
          className="theme-btn"
          onClick={toggleTheme}
        >

          {darkMode
            ? "☀️ Light Mode"
            : "🌙 Dark Mode"}

        </button>

        <h1>Weather App</h1>

        <input

          type="text"

          placeholder="Enter city"

          value={city}

          onChange={(e) =>
            setCity(e.target.value)
          }

          onKeyDown={(e) => {

            if(e.key === "Enter"){

              getWeather();

            }

          }}
        />

        <button

          className="search-btn"

          onClick={getWeather}

        >
          Search
        </button>

        {weather && (

          <div className="card">

            <h2>
              {weather.name}
            </h2>

            <h3>
              {Math.round(weather.main.temp)}°C
            </h3>

            <p>
              🌤️ {weather.weather[0].main}
            </p>

            <p>
              💧 Humidity:
              {" "}
              {weather.main.humidity}%
            </p>

            <p>
              🌬️ Wind Speed:
              {" "}
              {weather.wind.speed} m/s
            </p>

          </div>

        )}

      </div>

    </div>
  );
}

export default App;
